import Carousel from '@brainhubeu/react-carousel';
import '@brainhubeu/react-carousel/lib/style.css';
import React from 'react'

import ImageCard from "./ImageCard.js"
class ImageGallery extends React.Component {
    constructor() {
        super();
        this.state = {
            value : 1
        }
        this.onChange = this.onChange.bind(this);
    }
    /**
     * Executed when a user changes the image in the carousel
     * @param {*} val 
     */
    onChange(value) {
        this.setState({
            value
        });
    }

    isVisible(id) {
        return id == this.state.value;
    }

    render() {
        return (
            
        <Carousel 
            value={this.state.value}
            onChange={this.onChange} 
            plugins={['arrows', 'clickToChange']}
            slides={[
                (<ImageCard URL="art/1.jpg" visible={this.isVisible(0)}/>),
                (<ImageCard URL="art/2.jpg" visible={this.isVisible(1)}/>),
                (<ImageCard URL="art/3.jpg" visible={this.isVisible(2)}/>),
                (<ImageCard URL="art/4.jpg" visible={this.isVisible(3)}/>),
                (<ImageCard URL="art/5.jpg" visible={this.isVisible(4)}/>),
                (<ImageCard URL="art/6.jpg" visible={this.isVisible(5)}/>),
                (<ImageCard URL="art/7.jpg" visible={this.isVisible(6)}/>),
                (<ImageCard URL="art/8.jpg" visible={this.isVisible(7)}/>),
                (<ImageCard URL="art/9.jpg" visible={this.isVisible(8)}/>),
            ]}>
        </Carousel>
        );
    }

}

export default ImageGallery;